#!/usr/bin/env python3
"""Generate OA's public and private Python typing stubs from the live bindings."""

from __future__ import annotations

import argparse
import ast
import keyword
from pathlib import Path
import re
import shutil
import sys
import tempfile
from types import ModuleType

from nanobind.stubgen import StubGen


REPO_ROOT = Path(__file__).resolve().parents[2]
PACKAGE_ROOT = REPO_ROOT / "Source" / "Python" / "oa"
GENERATED_HEADER = (
	"# AUTO-GENERATED by Tools/Python/oapystubgen.py — DO NOT EDIT.\n"
	"# Sources of truth: the live nanobind signatures and oa/_surface.py.\n\n"
)


def _sanitize_python_keywords(source: str) -> str:
	"""Make C++ identifiers that are Python keywords valid in a stub."""

	for name in keyword.kwlist:
		source = re.sub(
			rf"(?m)^([ \t]+){re.escape(name)} = .*$",
			rf'\1# Runtime member "{name}" is available through getattr().',
			source,
		)
		source = source.replace(
			f".{name}", f'.__members__["{name}"]'
		)
	return source


def _use_tab_indentation(source: str) -> str:
	"""Use one tab for each four-space block emitted by nanobind stubgen."""

	return re.sub(
		r"(?m)^(?: {4})+",
		lambda match: "\t" * (len(match.group(0)) // 4),
		source,
	)


def _write_module_stub(
	module: ModuleType, output_file: Path, *, recursive: bool
) -> None:
	output_file.parent.mkdir(parents=True, exist_ok=True)
	generator = StubGen(
		module=module,
		recursive=recursive,
		include_docstrings=True,
		include_private=False,
		include_internal_imports=True,
		include_external_imports=False,
		max_expr_length=0,
		quiet=True,
		output_file=output_file,
	)
	generator.put(module)
	output_file.write_text(
		_use_tab_indentation(_sanitize_python_keywords(generator.get())),
		encoding="utf-8",
	)


def _declared_root_names(root_stub: Path) -> set[str]:
	tree = ast.parse(root_stub.read_text(encoding="utf-8"), filename=str(root_stub))
	names: set[str] = set()
	for node in tree.body:
		if isinstance(node, (ast.ClassDef, ast.FunctionDef, ast.AsyncFunctionDef)):
			names.add(node.name)
		elif isinstance(node, ast.ImportFrom):
			names.update(alias.asname or alias.name for alias in node.names)
		elif isinstance(node, ast.AnnAssign) and isinstance(node.target, ast.Name):
			names.add(node.target.id)
		elif isinstance(node, ast.Assign):
			names.update(
				target.id for target in node.targets if isinstance(target, ast.Name)
			)
	return names


def _generate_tree(output_root: Path) -> None:
	import oa
	from oa._native import native

	_write_module_stub(oa, output_root / "__init__.pyi", recursive=True)
	_write_module_stub(
		native, output_root / "_oa" / "__init__.pyi", recursive=True
	)

	for stub in sorted(output_root.rglob("*.pyi")):
		source = _use_tab_indentation(
			_sanitize_python_keywords(stub.read_text(encoding="utf-8"))
		)
		if not source.startswith(GENERATED_HEADER):
			source = GENERATED_HEADER + source
		stub.write_text(source, encoding="utf-8")
		ast.parse(stub.read_text(encoding="utf-8"), filename=str(stub))

	(output_root / "py.typed").write_text("", encoding="utf-8")

	declared = _declared_root_names(output_root / "__init__.pyi")
	missing = sorted(set(oa.__all__) - declared)
	if missing:
		raise RuntimeError(
			"generated root stub is missing public exports: " + ", ".join(missing)
		)

	namespace_stubs = {
		path.stem
		for path in output_root.glob("OaFn*.pyi")
		if path.is_file()
	}
	expected_namespaces = {name for name in oa.__all__ if name.startswith("OaFn")}
	if namespace_stubs != expected_namespaces:
		missing_namespaces = sorted(expected_namespaces - namespace_stubs)
		extra_namespaces = sorted(namespace_stubs - expected_namespaces)
		raise RuntimeError(
			"generated namespace stubs disagree with oa.__all__: "
			f"missing={missing_namespaces}, extra={extra_namespaces}"
		)


def _inventory(root: Path) -> dict[Path, bytes]:
	result = {
		path.relative_to(root): path.read_bytes()
		for path in root.rglob("*.pyi")
		if path.is_file()
	}
	marker = root / "py.typed"
	if marker.is_file():
		result[marker.relative_to(root)] = marker.read_bytes()
	return result


def _compare(expected_root: Path, actual_root: Path) -> list[str]:
	expected = _inventory(expected_root)
	actual = _inventory(actual_root)
	differences: list[str] = []
	for path in sorted(expected.keys() | actual.keys()):
		if path not in actual:
			differences.append(f"missing {path}")
		elif path not in expected:
			differences.append(f"stale {path}")
		elif expected[path] != actual[path]:
			differences.append(f"changed {path}")
	return differences


def _install(generated_root: Path) -> None:
	expected = _inventory(generated_root)
	existing = _inventory(PACKAGE_ROOT)

	for stale in sorted(existing.keys() - expected.keys()):
		(PACKAGE_ROOT / stale).unlink()
	for relative, content in expected.items():
		destination = PACKAGE_ROOT / relative
		destination.parent.mkdir(parents=True, exist_ok=True)
		if not destination.is_file() or destination.read_bytes() != content:
			destination.write_bytes(content)

	for directory in sorted(
		(path for path in PACKAGE_ROOT.rglob("*") if path.is_dir()),
		key=lambda path: len(path.parts),
		reverse=True,
	):
		if directory != PACKAGE_ROOT and not any(directory.iterdir()):
			directory.rmdir()


def main() -> int:
	parser = argparse.ArgumentParser(description=__doc__)
	parser.add_argument(
		"--check",
		action="store_true",
		help="fail when checked-in stubs differ from fresh generation",
	)
	args = parser.parse_args()

	with tempfile.TemporaryDirectory(prefix="oa-stubs-") as temporary:
		generated_root = Path(temporary)
		_generate_tree(generated_root)
		if args.check:
			differences = _compare(generated_root, PACKAGE_ROOT)
			if differences:
				for difference in differences:
					print(f"OA Python stub drift: {difference}", file=sys.stderr)
				return 1
		else:
			_install(generated_root)
	return 0


if __name__ == "__main__":
	raise SystemExit(main())
